using System;
using System.Collections.Generic;
using SwitchNro.Common.Logging;

namespace SwitchNro.Horizon;

/// <summary>
/// 内核对象基类
/// 表示可通过句柄引用的 Horizon 内核对象
/// </summary>
public abstract class KObject
{
    /// <summary>对象类型标识</summary>
    public abstract string ObjectType { get; }
}

/// <summary>
/// 可等待的内核对象接口
/// WaitSynchronization 只能等待实现了此接口的对象
/// 包括: KEvent, KReadableEvent, KClientSession 等
/// </summary>
public interface IWaitable
{
    /// <summary>对象是否已信号（可以被 WaitSynchronization 捕获）</summary>
    bool IsSignaled { get; }
}

/// <summary>
/// 客户端会话内核对象
/// ConnectToNamedPort 创建此对象，关联一个命名的 IPC 服务端口
/// </summary>
public sealed class KClientSession : KObject, IWaitable
{
    /// <summary>关联的服务端口名称（如 "sm:", "fs:"）</summary>
    public string ServicePortName { get; }

    public override string ObjectType => "ClientSession";

    /// <summary>会话是否可等待 — 在 HLE 模拟中，IPC 会话始终视为已信号（同步 IPC 模型）</summary>
    public bool IsSignaled => true;

    public KClientSession(string servicePortName)
    {
        ServicePortName = servicePortName;
    }
}

/// <summary>
/// 内核事件对象
/// 用于 WaitSynchronization 等同步操作
/// </summary>
public sealed class KEvent : KObject, IWaitable
{
    /// <summary>事件是否已信号</summary>
    public bool IsSignaled { get; set; }

    public override string ObjectType => "KEvent";

    public KEvent(bool signaled = false)
    {
        IsSignaled = signaled;
    }
}

/// <summary>
/// 线程活动状态（用于 SVC 0x40 SetThreadActivity）
/// 对应 Horizon 内核 ThreadActivity 枚举
/// </summary>
public enum ThreadActivity
{
    /// <summary>线程可被调度执行（默认状态）</summary>
    Runnable = 0,
    /// <summary>线程被暂停，不会被调度</summary>
    Paused = 1,
}

/// <summary>
/// 线程状态（对应 Horizon 内核 KThread 的运行时状态）
/// </summary>
public enum ThreadState
{
    /// <summary>线程已创建但尚未启动（StartThread 未调用）</summary>
    Created,
    /// <summary>线程正在运行或可被调度</summary>
    Running,
    /// <summary>线程被暂停（SetThreadActivity Paused），不会被调度</summary>
    Paused,
    /// <summary>线程已终止（正常退出或被杀死）</summary>
    Terminated,
}

/// <summary>
/// 内核线程对象
/// 表示进程中可调度的执行线程
/// 通过 Homebrew ABI 传递给 NRO 作为主线程句柄
/// 也可由 SVC 0x34 CreateThread 创建
/// </summary>
public sealed class KThread : KObject, IWaitable
{
    /// <summary>线程 ID</summary>
    public ulong ThreadId { get; }

    /// <summary>线程入口函数地址</summary>
    public ulong EntryPoint { get; }

    /// <summary>传递给入口函数的参数</summary>
    public ulong Argument { get; }

    /// <summary>栈顶地址（ARM64 栈向下增长，此值为栈区域末尾）</summary>
    public ulong StackTop { get; }

    /// <summary>栈区域基地址（用于释放时取消映射）</summary>
    public ulong StackBase { get; }

    /// <summary>栈大小（字节）</summary>
    public ulong StackSize { get; }

    /// <summary>线程优先级 (0-63，0 最低)</summary>
    public int Priority { get; set; }

    /// <summary>处理器亲和性核心 ID (0-3)，-2 = 任意核心</summary>
    public int ProcessorId { get; }

    /// <summary>线程的 TLS 区域基地址（每个线程 0x200 字节）</summary>
    public ulong TlsAddress { get; set; }

    /// <summary>线程当前运行状态</summary>
    public ThreadState State { get; set; } = ThreadState.Created;

    public override string ObjectType => "KThread";

    /// <summary>
    /// 线程是否可等待
    /// 真实 Horizon: KThread 句柄在线程终止时变为信号状态（用于 Join 语义）
    /// 当前单线程模型: 主线程始终视为已信号（简化 WaitSynchronization）
    /// CreateThread 创建的线程: 终止后变为已信号
    /// TODO: 多线程实现后，IsSignaled 应在线程终止时才为 true
    /// </summary>
    public bool IsSignaled => State == ThreadState.Terminated || _isMainThread;

    private readonly bool _isMainThread;

    /// <summary>
    /// 创建主线程 KThread（StartProcess 使用）
    /// 主线程始终视为已信号（简化 WaitSynchronization）
    /// </summary>
    public KThread(ulong threadId)
    {
        ThreadId = threadId;
        _isMainThread = true;
        State = ThreadState.Running;
        // 主线程的入口/栈/优先级等在 StartProcess 中通过 Engine 直接设置
        EntryPoint = 0;
        Argument = 0;
        StackTop = 0;
        StackBase = 0;
        StackSize = 0;
        Priority = 44; // 标准应用主线程优先级
        ProcessorId = 0;
    }

    /// <summary>
    /// 创建新线程 KThread（SVC 0x34 CreateThread 使用）
    /// </summary>
    public KThread(ulong threadId, ulong entryPoint, ulong argument, ulong stackTop,
        ulong stackBase, ulong stackSize, int priority, int processorId)
    {
        ThreadId = threadId;
        _isMainThread = false;
        State = ThreadState.Created;
        EntryPoint = entryPoint;
        Argument = argument;
        StackTop = stackTop;
        StackBase = stackBase;
        StackSize = stackSize;
        Priority = priority;
        ProcessorId = processorId;
    }
}

/// <summary>
/// 内核可等待事件对象（KEvent + 可读事件句柄的组合）
/// 部分 HLE 服务返回 KEvent 的可读事件句柄
/// </summary>
public sealed class KReadableEvent : KObject, IWaitable
{
    /// <summary>是否已信号</summary>
    public bool IsSignaled { get; set; }

    public override string ObjectType => "ReadableEvent";

    public KReadableEvent(bool signaled = false)
    {
        IsSignaled = signaled;
    }
}

/// <summary>
/// 进程内核句柄表
/// 管理进程内所有的内核对象句柄映射
/// 句柄 ID 从 0xD000 开始递增（与 Horizon OS 行为一致）
/// </summary>
public sealed class HandleTable
{
    private readonly Dictionary<int, KObject> _handles = new();
    private int _nextHandle = 0xD000;

    /// <summary>当前有效句柄数</summary>
    public int Count => _handles.Count;

    /// <summary>
    /// 创建新句柄并注册内核对象
    /// </summary>
    /// <param name="obj">要注册的内核对象</param>
    /// <returns>分配的句柄 ID</returns>
    public int CreateHandle(KObject obj)
    {
        int handle = _nextHandle++;
        _handles[handle] = obj;
        Logger.Debug(nameof(HandleTable), $"创建句柄 0x{handle:X8} → {obj.ObjectType}");
        return handle;
    }

    /// <summary>
    /// 获取句柄对应的内核对象
    /// </summary>
    /// <param name="handle">句柄 ID</param>
    /// <returns>内核对象，如果句柄无效则返回 null</returns>
    public KObject? GetObject(int handle)
    {
        return _handles.TryGetValue(handle, out var obj) ? obj : null;
    }

    /// <summary>
    /// 获取句柄对应的特定类型内核对象
    /// </summary>
    /// <typeparam name="T">期望的内核对象类型</typeparam>
    /// <param name="handle">句柄 ID</param>
    /// <returns>类型匹配的内核对象，如果句柄无效或类型不匹配则返回 null</returns>
    public T? GetObject<T>(int handle) where T : KObject
    {
        return GetObject(handle) as T;
    }

    /// <summary>
    /// 关闭句柄并移除内核对象引用
    /// </summary>
    /// <param name="handle">要关闭的句柄 ID</param>
    /// <returns>是否成功关闭</returns>
    public bool CloseHandle(int handle)
    {
        if (!_handles.Remove(handle))
        {
            Logger.Warning(nameof(HandleTable), $"关闭无效句柄: 0x{handle:X8}");
            return false;
        }

        Logger.Debug(nameof(HandleTable), $"关闭句柄 0x{handle:X8}");
        return true;
    }

    /// <summary>
    /// 检查句柄是否有效
    /// </summary>
    public bool IsValid(int handle) => _handles.ContainsKey(handle);

    /// <summary>
    /// 清空所有句柄
    /// </summary>
    public void Clear()
    {
        _handles.Clear();
    }
}

using System;
using System.Buffers.Binary;
using System.Text;
using SwitchNro.Common;
using SwitchNro.Common.Logging;
using SwitchNro.Memory;

namespace SwitchNro.HLE.Ipc;

/// <summary>
/// IPC 消息解析器
/// 解析/写入 Horizon OS 的 IPC 二进制协议（CMIF 和 TIPC 格式）
/// 从 guest 虚拟内存中读取请求、写入响应
/// 
/// ──────────────────── CMIF 请求布局 ────────────────────
///  偏移 0x00: uint32 Word0 (Type[0:15] | X_count[16:19] | A_count[20:23] | B_count[24:27] | W_count[28:31])
///  偏移 0x04: uint32 Word1 (RawDataSize[0:9] | RecvListFlags[10:13] | Reserved[14:30] | HndDescEnable[31])
///  偏移 0x08: Handle Descriptor (如果 HndDescEnable):
///               uint32 word (HasPId[0] | CopyCount[1:4] | MoveCount[5:8])
///               ulong PId (如果 HasPId)
///               uint32[] CopyHandles
///               uint32[] MoveHandles
///  偏移 ...  : X 指针缓冲区描述符: IpcPtrBuffDesc[] (8 字节/个, 2 × uint32)
///  偏移 ...  : A 发送缓冲区描述符: IpcBuffDesc[] (12 字节/个, 3 × uint32)
///  偏移 ...  : B 接收缓冲区描述符: IpcBuffDesc[] (12 字节/个, 3 × uint32)
///  偏移 ...  : W 交换缓冲区描述符: IpcBuffDesc[] (12 字节/个, 3 × uint32)
///  偏移 ...  : 16 字节对齐填充
///  偏移 ...  : RawData 数据载荷 (第一个 uint 通常是 commandId)
///  偏移 ...  : C 接收列表缓冲区描述符: IpcRecvListBuffDesc[] (8 字节/个)
/// ────────────────────────────────────────────────────────
/// </summary>
public static class IpcMessageParser
{
    /// <summary>IPC 缓冲区最大大小（TLS 区域通常 0x100 字节）</summary>
    private const int IpcBufferSize = 0x100;

    // CMIF 头部固定区域大小 (2 × uint32 = 8 bytes)
    private const int CmifHeaderSize = 0x08;

    // TIPC 头部固定区域大小 (4 × uint32 = 16 bytes)
    private const int TipcHeaderSize = 0x10;

    // IpcBuffDesc 大小 (3 × uint32 = 12 bytes)
    private const int BuffDescSize = 12;

    // IpcPtrBuffDesc 大小 (2 × uint32 = 8 bytes)
    private const int PtrBuffDescSize = 8;

    // IpcRecvListBuffDesc 大小 (1 × uint64 = 8 bytes)
    private const int RecvListBuffDescSize = 8;

    /// <summary>
    /// 快速从 IPC 缓冲区读取命令 ID
    /// </summary>
    public static uint ReadCommandId(ulong bufferAddr, VirtualMemoryManager memory)
    {
        try
        {
            var headerBuf = new byte[8];
            memory.Read(bufferAddr, headerBuf);
            uint word0 = BinaryPrimitives.ReadUInt32LittleEndian(headerBuf.AsSpan(0));
            uint word1 = BinaryPrimitives.ReadUInt32LittleEndian(headerBuf.AsSpan(4));
            var header = new IpcMessageHeader(word0, word1);

            if (header.CommandType is IpcCommandType.TipcRequest or IpcCommandType.TipcControl)
                return header.TipcCommandId;

            // CMIF: 跳过 Header 和句柄描述符
            int offset = CmifHeaderSize;
            if (header.HndDescEnable)
            {
                var hndWordBuf = new byte[4];
                memory.Read(bufferAddr + (ulong)offset, hndWordBuf);
                uint hndWord = BinaryPrimitives.ReadUInt32LittleEndian(hndWordBuf);
                bool hasPid = (hndWord & 1) != 0;
                int copyCount = (int)((hndWord >> 1) & 0xF);
                int moveCount = (int)((hndWord >> 5) & 0xF);
                offset += 4 + (hasPid ? 8 : 0) + (copyCount + moveCount) * 4;
            }

            // 跳过 X 描述符 (每个 8 字节)
            offset += header.PtrBuffCount * 8;
            // 跳过 A, B, W 描述符 (每个 12 字节)
            offset += (header.SendBuffCount + header.RecvBuffCount + header.XchgBuffCount) * 12;
            // 16 字节对齐
            offset = (offset + 15) & ~15;

            var cmdIdBuf = new byte[4];
            memory.Read(bufferAddr + (ulong)offset, cmdIdBuf);
            return BinaryPrimitives.ReadUInt32LittleEndian(cmdIdBuf);
        }
        catch { return 0; }
    }

    /// <summary>
    /// 从 guest 内存解析 IPC 请求
    /// </summary>
    public static IpcRequest ParseRequest(ulong bufferAddr, VirtualMemoryManager memory)
    {
        // 读取整个 IPC 缓冲区
        var buffer = new byte[IpcBufferSize];
        memory.Read(bufferAddr, buffer);

        // CMIF: Word0 + Word1
        uint word0 = ReadUInt32(buffer, 0);
        uint word1 = ReadUInt32(buffer, 4);
        var header = new IpcMessageHeader(word0, word1);
        var cmdType = header.CommandType;

        Logger.Debug(nameof(IpcMessageParser),
            $"解析 IPC 请求 @ 0x{bufferAddr:X16}: type={cmdType} w0=0x{word0:X8} w1=0x{word1:X8}");

        // TIPC 格式（TipcRequest / TipcClose / TipcControl）
        if (cmdType is IpcCommandType.TipcRequest or IpcCommandType.TipcClose or IpcCommandType.TipcControl)
        {
            return ParseTipcRequest(buffer, header);
        }

        // CMIF 格式（Request / Control / Close / Legacy 等）
        return ParseCmifRequest(buffer, header);
    }

    /// <summary>
    /// 将 IPC 响应写入 guest 内存
    /// </summary>
    public static void WriteResponse(ulong bufferAddr, VirtualMemoryManager memory,
        IpcResponse response, IpcCommandType cmdType)
    {
        // 清空缓冲区
        var buffer = new byte[IpcBufferSize];

        if (cmdType is IpcCommandType.TipcRequest or IpcCommandType.TipcClose or IpcCommandType.TipcControl)
        {
            WriteTipcResponse(buffer, response, cmdType);
        }
        else
        {
            WriteCmifResponse(buffer, response, cmdType);
        }

        memory.Write(bufferAddr, buffer);

        Logger.Debug(nameof(IpcMessageParser),
            $"写入 IPC 响应 @ 0x{bufferAddr:X16}: type={cmdType} data={response.Data.Count}B handles={response.CopyHandles.Count}");
    }

    // ──────────────────── CMIF 请求解析 ────────────────────

    private static IpcRequest ParseCmifRequest(byte[] buffer, IpcMessageHeader header)
    {
        var cmdType = header.CommandType;

        // 从头部提取缓冲区描述符数量
        int xCount = header.PtrBuffCount;
        int aCount = header.SendBuffCount;
        int bCount = header.RecvBuffCount;
        int wCount = header.XchgBuffCount;

        // 数据大小（以字为单位）
        int dataSizeWords = header.RawDataSizeWords;
        int dataSize = dataSizeWords * 4;

        // 当前读取偏移（从头部固定区域之后开始）
        int offset = CmifHeaderSize;

        // ──────── 句柄描述符 ────────
        ulong clientPid = 0;
        int[] copyHandles = [];
        int[] moveHandles = [];

        if (header.HndDescEnable)
        {
            var (handleDesc, bytesRead) = IpcHandleDesc.Parse(buffer, offset);
            offset += bytesRead;

            clientPid = handleDesc.HasPId ? handleDesc.PId : 0;
            copyHandles = handleDesc.CopyHandles;
            moveHandles = handleDesc.MoveHandles;
        }

        // ──────── X 指针缓冲区描述符（第一个，8 字节/个）────────
        int xRead = 0;
        var ptrBuffers = new IpcPtrBuffDesc[xCount];
        for (int i = 0; i < xCount && offset + PtrBuffDescSize <= buffer.Length; i++)
        {
            uint w0 = ReadUInt32(buffer, offset);
            uint w1 = ReadUInt32(buffer, offset + 4);
            ptrBuffers[i] = IpcPtrBuffDesc.FromWords(w0, w1);
            offset += PtrBuffDescSize;
            xRead++;
        }
        // 跳过因缓冲区不足而未读取的 X 描述符空间
        int xSkipped = xCount - xRead;
        if (xSkipped > 0 && offset + xSkipped * PtrBuffDescSize <= buffer.Length)
            offset += xSkipped * PtrBuffDescSize;

        // ──────── A 发送缓冲区描述符（12 字节/个）────────
        int aRead = 0;
        var sendBuffers = new IpcBuffDesc[aCount];
        for (int i = 0; i < aCount && offset + BuffDescSize <= buffer.Length; i++)
        {
            uint w0 = ReadUInt32(buffer, offset);
            uint w1 = ReadUInt32(buffer, offset + 4);
            uint w2 = ReadUInt32(buffer, offset + 8);
            sendBuffers[i] = IpcBuffDesc.FromWords(w0, w1, w2);
            offset += BuffDescSize;
            aRead++;
        }
        if (aCount - aRead > 0 && offset + (aCount - aRead) * BuffDescSize <= buffer.Length)
            offset += (aCount - aRead) * BuffDescSize;

        // ──────── B 接收缓冲区描述符（12 字节/个）────────
        int bRead = 0;
        var recvBuffers = new IpcBuffDesc[bCount];
        for (int i = 0; i < bCount && offset + BuffDescSize <= buffer.Length; i++)
        {
            uint w0 = ReadUInt32(buffer, offset);
            uint w1 = ReadUInt32(buffer, offset + 4);
            uint w2 = ReadUInt32(buffer, offset + 8);
            recvBuffers[i] = IpcBuffDesc.FromWords(w0, w1, w2);
            offset += BuffDescSize;
            bRead++;
        }
        if (bCount - bRead > 0 && offset + (bCount - bRead) * BuffDescSize <= buffer.Length)
            offset += (bCount - bRead) * BuffDescSize;

        // ──────── W 交换缓冲区描述符（12 字节/个）────────
        int wRead = 0;
        var exchangeBuffers = new IpcBuffDesc[wCount];
        for (int i = 0; i < wCount && offset + BuffDescSize <= buffer.Length; i++)
        {
            uint w0 = ReadUInt32(buffer, offset);
            uint w1 = ReadUInt32(buffer, offset + 4);
            uint w2 = ReadUInt32(buffer, offset + 8);
            exchangeBuffers[i] = IpcBuffDesc.FromWords(w0, w1, w2);
            offset += BuffDescSize;
            wRead++;
        }
        if (wCount - wRead > 0 && offset + (wCount - wRead) * BuffDescSize <= buffer.Length)
            offset += (wCount - wRead) * BuffDescSize;

        // ──────── 16 字节对齐填充 ────────
        int pad = GetPadSize16(offset);
        offset += pad;

        // 保存 C 描述符的起始位置（在 rawData 之后）
        int recvListPos = offset + dataSize;

        // ──────── RawData 数据载荷 ────────
        byte[] rawData = [];
        if (dataSize > 0 && offset + dataSize <= buffer.Length)
        {
            rawData = new byte[dataSize];
            Array.Copy(buffer, offset, rawData, 0, dataSize);
        }
        else if (dataSize > 0)
        {
            int availSize = Math.Max(0, buffer.Length - offset);
            if (availSize > 0)
            {
                rawData = new byte[availSize];
                Array.Copy(buffer, offset, rawData, 0, availSize);
            }
        }

        // ──────── C 接收列表缓冲区描述符 ────────
        int recvListFlags = header.RecvListFlags;
        int cCount = ComputeRecvListCount(recvListFlags);

        var recvListBuffers = new IpcRecvListBuffDesc[cCount];
        int cOffset = Math.Min(recvListPos, buffer.Length);
        for (int i = 0; i < cCount && cOffset + RecvListBuffDescSize <= buffer.Length; i++)
        {
            ulong raw = ReadUInt64(buffer, cOffset);
            recvListBuffers[i] = new IpcRecvListBuffDesc(raw);
            cOffset += RecvListBuffDescSize;
        }

        // 从数据载荷提取 commandId（CMIF Request 的数据前 4 字节为 commandId）
        uint commandId = 0;
        byte[] data = [];
        if (rawData.Length >= 4)
        {
            commandId = ReadUInt32(rawData, 0);
            data = new byte[rawData.Length - 4];
            if (data.Length > 0)
                Array.Copy(rawData, 4, data, 0, data.Length);
        }
        else if (rawData.Length > 0)
        {
            data = rawData;
        }

        Logger.Debug(nameof(IpcMessageParser),
            $"CMIF 请求: cmdType={cmdType} cmdId={commandId} pid={clientPid} " +
            $"copyH={copyHandles.Length} moveH={moveHandles.Length} " +
            $"X={xCount} A={aCount} B={bCount} W={wCount} C={recvListBuffers.Length} " +
            $"dataSize={dataSize}");

        return new IpcRequest
        {
            Header = header,
            CommandId = commandId,
            ClientPid = clientPid,
            Data = data,
            CopyHandles = copyHandles,
            MoveHandles = moveHandles,
            SendBuffers = sendBuffers,
            ReceiveBuffers = recvBuffers,
            ExchangeBuffers = exchangeBuffers,
            PointerBuffers = ptrBuffers,
            RecvListBuffers = recvListBuffers,
        };
    }

    // ──────────────────── TIPC 请求解析 ────────────────────

    private static IpcRequest ParseTipcRequest(byte[] buffer, IpcMessageHeader header)
    {
        // TIPC 格式: header(4) + padding(4) + padding(4) + padding(4) + data...
        // Type 在 Word0[0:15], CommandId 在 Word0[16:31]
        uint commandId = header.TipcCommandId;

        int offset = TipcHeaderSize;

        // 数据载荷
        int remaining = Math.Min(buffer.Length - offset, IpcBufferSize - offset);
        byte[] data = [];
        if (remaining > 0)
        {
            data = new byte[remaining];
            Array.Copy(buffer, offset, data, 0, remaining);
        }

        // TIPC 请求中的 handles 简化处理
        var copyHandles = Array.Empty<int>();
        var moveHandles = Array.Empty<int>();

        Logger.Debug(nameof(IpcMessageParser),
            $"TIPC 请求: cmdType={header.CommandType} cmdId={commandId} dataSize={data.Length}");

        return new IpcRequest
        {
            Header = header,
            CommandId = commandId,
            ClientPid = 0,
            Data = data,
            CopyHandles = copyHandles,
            MoveHandles = moveHandles,
        };
    }

    // ──────────────────── CMIF 响应写入 ────────────────────

    private static void WriteCmifResponse(byte[] buffer, IpcResponse response, IpcCommandType cmdType)
    {
        int copyHandleCount = response.CopyHandles.Count;
        // 数据载荷包含: result code (4 bytes) + response.Data，向上对齐到 4 字节
        int totalDataSize = 4 + response.Data.Count;
        int dataSizeWords = (totalDataSize + 3) / 4;

        // 构建 CMIF 响应头
        // Word0: Type[0:15] (与 CMIF 请求相同, 含完整 command type)
        // Word1: RawDataSize[0:9] | HndDescEnable[31]
        uint word0 = (uint)cmdType & 0xFFFF;
        uint word1 = (uint)(dataSizeWords & 0x3FF);
        if (copyHandleCount > 0)
            word1 |= 0x80000000u; // HndDescEnable

        WriteUInt32(buffer, 0, word0);
        WriteUInt32(buffer, 4, word1);

        int offset = CmifHeaderSize;

        // 句柄描述符（如果需要）
        if (copyHandleCount > 0)
        {
            var handleDesc = new IpcHandleDesc(response.CopyHandles.ToArray(), [], 0, false);
            handleDesc.Write(buffer, offset);
            offset += handleDesc.Size;
        }

        // RawData（result code 作为数据载荷的第一个 uint32）
        // 注意: 响应写入不使用 16 字节对齐填充 — Horizon 响应格式中 rawData 紧跟句柄描述符之后
        WriteUInt32(buffer, offset, (uint)response.ResultCode.Value);
        offset += 4;

        if (response.Data.Count > 0)
        {
            int copyLen = Math.Min(response.Data.Count, buffer.Length - offset);
            if (copyLen > 0)
            {
                response.Data.CopyTo(0, buffer, offset, copyLen);
                offset += copyLen;
            }
        }
    }

    // ──────────────────── TIPC 响应写入 ────────────────────

    private static void WriteTipcResponse(byte[] buffer, IpcResponse response, IpcCommandType cmdType)
    {
        int dataSizeWords = (response.Data.Count + 7) / 4; // 含 result code

        // TIPC 响应头: Type[0:15] | DataSizeWords[16:31]
        uint word0 = ((uint)cmdType & 0xFFFF) | ((uint)(dataSizeWords & 0xFFFF) << 16);
        WriteUInt32(buffer, 0, word0);

        // 结果码
        WriteUInt32(buffer, 4, (uint)response.ResultCode.Value);
        // padding
        WriteUInt32(buffer, 8, 0);
        WriteUInt32(buffer, 12, 0);

        int offset = TipcHeaderSize;

        // Copy handles (TIPC 通常无句柄)
        foreach (var handle in response.CopyHandles)
        {
            if (offset + 4 > buffer.Length) break;
            WriteUInt32(buffer, offset, (uint)handle);
            offset += 4;
        }

        // 数据载荷
        if (response.Data.Count > 0)
        {
            int copyLen = Math.Min(response.Data.Count, buffer.Length - offset);
            if (copyLen > 0)
            {
                response.Data.CopyTo(0, buffer, offset, copyLen);
            }
        }
    }

    // ──────────────────── 辅助方法 ────────────────────

    /// <summary>
    /// 计算 C 接收列表描述符数量
    /// recvListFlags == 0: 无 C 描述符
    /// recvListFlags == 1: 无 C 描述符
    /// recvListFlags == 2: 1 个 C 描述符
    /// recvListFlags > 2: (recvListFlags - 2) 个 C 描述符
    /// </summary>
    private static int ComputeRecvListCount(int recvListFlags)
    {
        int count = recvListFlags - 2;
        if (count == 0) count = 1;
        else if (count < 0) count = 0;
        return count;
    }

    /// <summary>
    /// 计算 16 字节对齐填充大小
    /// </summary>
    private static int GetPadSize16(int position)
    {
        int mask = position & 0xF;
        return mask != 0 ? 0x10 - mask : 0;
    }

    /// <summary>
    /// 从 IPC 请求数据中读取服务名称
    /// 通常位于 data[0..7]（8 字节 null-terminated ASCII）
    /// </summary>
    public static string ReadServiceName(byte[] data)
    {
        if (data.Length < 8) return "";
        // 跳过前 4 字节的 commandId/padding，读取后续 8 字节
        // sm:GetService 的 data 格式: [4字节 padding] + [8字节 服务名]
        int nameOffset = data.Length >= 12 ? 4 : 0;
        int nameLen = Math.Min(8, data.Length - nameOffset);
        var nameBytes = new byte[nameLen];
        Array.Copy(data, nameOffset, nameBytes, 0, nameLen);
        return Encoding.ASCII.GetString(nameBytes).TrimEnd('\0');
    }

    /// <summary>从字节数组指定偏移读取 UInt32（小端序）</summary>
    private static uint ReadUInt32(byte[] buffer, int offset)
        => BinaryPrimitives.ReadUInt32LittleEndian(buffer.AsSpan(offset));

    /// <summary>向字节数组指定偏移写入 UInt32（小端序）</summary>
    private static void WriteUInt32(byte[] buffer, int offset, uint value)
        => BinaryPrimitives.WriteUInt32LittleEndian(buffer.AsSpan(offset), value);

    /// <summary>从字节数组指定偏移读取 UInt64（小端序）</summary>
    private static ulong ReadUInt64(byte[] buffer, int offset)
        => BinaryPrimitives.ReadUInt64LittleEndian(buffer.AsSpan(offset));
}

using System;
using System.Runtime.InteropServices;
using SwitchNro.Common.Logging;
using SwitchNro.Memory;

namespace SwitchNro.Horizon;

// ──────────────────── Homebrew ABI 常量 ────────────────────

/// <summary>
/// Homebrew ABI 配置条目类型（EntryType）
/// 与 libnx switch/runtime/env.h 中的定义一致
/// </summary>
public static class HbEntryType
{
    /// <summary>条目列表结束标记</summary>
    public const uint EndOfList = 0;
    /// <summary>主线程句柄 — Value[0] = 线程句柄 (u64)</summary>
    public const uint MainThreadHandle = 1;
    /// <summary>下一个加载路径 — Value[0] = 路径字符串指针</summary>
    public const uint NextLoadPath = 2;
    /// <summary>堆大小覆盖 — Value[0] = 堆大小 (u64), Value[1] = 堆地址 (如果适用)</summary>
    public const uint OverrideHeap = 3;
    /// <summary>服务覆盖 — Value[0] = 服务名称/覆盖指针</summary>
    public const uint OverrideService = 4;
    /// <summary>命令行参数</summary>
    public const uint Argv = 5;
    /// <summary>系统调用可用性提示</summary>
    public const uint SyscallAvailableHint = 6;
    /// <summary>Applet 类型</summary>
    public const uint AppletType = 7;
    /// <summary>ApmStateAndTev</summary>
    public const uint ApmStateAndTev = 8;
    /// <summary>随机种子</summary>
    public const uint RandomSeed = 9;
    /// <summary>HostConnection</summary>
    public const uint HostConnection = 10;
    /// <summary>HOS 版本 — Value[0] = 版本号 (u64, 格式: major<<16 | minor<<8 | micro)</summary>
    public const uint HosVersion = 11;
}

/// <summary>
/// Homebrew ABI 配置条目标志位
/// </summary>
public static class HbConfigFlags
{
    /// <summary>无标志</summary>
    public const uint None = 0;
    /// <summary>此条目是必需的，缺失时 libnx envInitialize() 应失败</summary>
    public const uint Mandatory = 1;
}

// ──────────────────── ConfigEntry 结构体 ────────────────────

/// <summary>
/// Homebrew ABI 配置条目 (40 字节)
/// 布局: Key(u32) + Flags(u32) + Value[4](u64×4)
/// 注意：在 AArch64 上，Value 数组会自动对齐到 8 字节边界。
/// </summary>
[StructLayout(LayoutKind.Sequential)]
public struct HbConfigEntry
{
    public uint Key;
    public uint Flags;
    public ulong Value0;
    public ulong Value1;
    public ulong Value2;
    public ulong Value3;

    public static int StructSize => 40; // 4+4 + 8*4
}

// ──────────────────── LoaderConfig 构建器 ────────────────────

/// <summary>
/// Homebrew ABI loader_config 构建器
/// 在 guest 内存中构建 ConfigEntry 数组，供 NRO 入口点读取
/// 
/// 调用约定:
///   X0 = loader_config 结构指针
///   X1 = 0xFFFFFFFFFFFFFFFF (哨兵值，标识 Homebrew ABI 模式)
/// </summary>
public sealed class HomebrewLoaderConfig
{
    private readonly VirtualMemoryManager _memory;
    private readonly List<HbConfigEntry> _entries = new();

    /// <summary>loader_config 在 guest 内存中的基地址</summary>
    public ulong BaseAddress { get; private set; }

    /// <summary>loader_config 总大小（字节）</summary>
    public int TotalSize => _entries.Count * HbConfigEntry.StructSize;

    public HomebrewLoaderConfig(VirtualMemoryManager memory)
    {
        _memory = memory;
    }

    /// <summary>添加主线程句柄条目</summary>
    public HomebrewLoaderConfig AddMainThreadHandle(int threadHandle)
    {
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.MainThreadHandle,
            Flags = HbConfigFlags.Mandatory,
            Value0 = (ulong)threadHandle,
        });
        return this;
    }

    /// <summary>添加堆大小条目</summary>
    public HomebrewLoaderConfig AddHeapSize(ulong heapSize)
    {
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.OverrideHeap,
            Flags = HbConfigFlags.Mandatory,
            Value0 = heapSize,
            Value1 = 0,
        });
        return this;
    }

    /// <summary>
    /// 添加系统版本条目
    /// </summary>
    /// <param name="major">系统版本主号 (如 18)</param>
    /// <param name="minor">系统版本次号 (如 1)</param>
    /// <param name="micro">系统版本微号 (如 0)</param>
    public HomebrewLoaderConfig AddSystemVersion(byte major, byte minor, byte micro)
    {
        // Horizon 系统版本编码: (major << 16) | (minor << 8) | micro
        ulong version = ((ulong)major << 16) | ((ulong)minor << 8) | micro;
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.HosVersion,
            Flags = HbConfigFlags.Mandatory,
            Value0 = version,
        });
        return this;
    }

    /// <summary>添加 Applet 类型条目</summary>
    public HomebrewLoaderConfig AddAppletType(uint appletType)
    {
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.AppletType,
            Flags = 0,
            Value0 = (ulong)appletType,
        });
        return this;
    }

    /// <summary>添加系统调用可用性提示</summary>
    public HomebrewLoaderConfig AddSyscallAvailableHint(ulong mask0, ulong mask1)
    {
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.SyscallAvailableHint,
            Flags = 0,
            Value0 = mask0,
            Value1 = mask1,
        });
        return this;
    }

    /// <summary>添加随机种子条目</summary>
    public HomebrewLoaderConfig AddRandomSeed(ulong seed0, ulong seed1)
    {
        _entries.Add(new HbConfigEntry
        {
            Key = HbEntryType.RandomSeed,
            Flags = 0,
            Value0 = seed0,
            Value1 = seed1,
        });
        return this;
    }

    /// <summary>
    /// 写入 loader_config 到 guest 内存
    /// 自动添加 EndOfList 终止条目，并在指定基地址分配内存
    /// </summary>
    /// <param name="baseAddress">loader_config 在 guest 内存中的基地址</param>
    /// <returns>基地址（即传入的 baseAddress）</returns>
    public ulong WriteToMemory(ulong baseAddress)
    {
        BaseAddress = baseAddress;

        // 添加 EndOfList 终止条目
        var allEntries = new List<HbConfigEntry>(_entries)
        {
            new HbConfigEntry
            {
                Key = HbEntryType.EndOfList,
                Flags = 0,
            }
        };

        int totalSize = allEntries.Count * HbConfigEntry.StructSize;

        // 映射内存页（RW 权限，供 guest 读取）
        // 如果页已映射（可能与其他分配重叠），跳过映射
        ulong alignedAddr = baseAddress & ~0xFFFUL; // 4KB 对齐 (VMM 页粒度)
        ulong endAddr = (baseAddress + (ulong)totalSize + 0xFFFUL) & ~0xFFFUL;
        ulong mapSize = endAddr - alignedAddr;

        if (!_memory.IsMapped(alignedAddr))
        {
            _memory.MapZero(alignedAddr, mapSize, MemoryPermissions.ReadWrite, MemoryType.Normal);
        }

        // 逐条写入 ConfigEntry
        ulong offset = 0;
        foreach (var entry in allEntries)
        {
            _memory.Write(baseAddress + offset, entry);
            offset += (ulong)HbConfigEntry.StructSize;
        }

        Logger.Info(nameof(HomebrewLoaderConfig),
            $"loader_config 写入 0x{baseAddress:X16}, {_entries.Count} 个条目 + EndOfList, " +
            $"总大小 {totalSize} 字节");

        return baseAddress;
    }
}

using System;
using System.Text;
using SwitchNro.Common;
using SwitchNro.Common.Logging;
using SwitchNro.Cpu;
using SwitchNro.Horizon;
using SwitchNro.Memory;

namespace SwitchNro.HLE.Ipc;

/// <summary>
/// IPC 桥接器
/// 将 guest NRO 的 SVC 系统调用桥接到 HLE 服务层
/// 处理 ConnectToNamedPort、SendSyncRequest/WithUserBuffer、
/// ReplyAndReceive/WithUserBuffer
/// </summary>
public sealed class IpcBridge
{
    private readonly IpcServiceManager _serviceManager;
    private readonly VirtualMemoryManager _memory;

    /// <summary>
    /// 当前进程的句柄表（由外部设置，因为进程在 NRO 加载时才创建）
    /// </summary>
    public HandleTable? ActiveHandleTable { get; set; }

    /// <summary>
    /// 当前进程的 TLS 地址（IPC 缓冲区在 TLS + 0x100）
    /// </summary>
    public ulong ActiveTlsAddress { get; set; }

    public IpcBridge(IpcServiceManager serviceManager, VirtualMemoryManager memory)
    {
        _serviceManager = serviceManager;
        _memory = memory;
    }

    /// <summary>
    /// 绑定当前活跃进程的上下文
    /// </summary>
    public void BindProcess(HorizonProcess process)
    {
        ActiveHandleTable = process.HandleTable;
        ActiveTlsAddress = process.TlsAddress;
    }

    // ──────────────────── SvcConnectToNamedPort (0x1F) ────────────────────

    /// <summary>
    /// 处理 SvcConnectToNamedPort
    /// X0 = 指向服务名称的指针（null-terminated ASCII，8 字节对齐）
    /// 成功: X0 = 0 (Success), X1 = ClientSession 句柄
    /// 失败: X0 = 错误码
    /// </summary>
    public SvcResult ConnectToNamedPort(SvcInfo svc)
    {
        if (ActiveHandleTable == null)
        {
            Logger.Error(nameof(IpcBridge), "ConnectToNamedPort: 无活跃进程句柄表");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidState) };
        }

        ulong nameAddr = svc.X0;
        if (nameAddr == 0)
        {
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidAddress) };
        }

        string serviceName = ReadServiceNameFromGuest(nameAddr);
        Logger.Info(nameof(IpcBridge), $"ConnectToNamedPort: \"{serviceName}\" @ 0x{nameAddr:X16}");

        var service = _serviceManager.GetService(serviceName);
        if (service == null)
        {
            Logger.Warning(nameof(IpcBridge), $"服务未找到: \"{serviceName}\"");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.NotImplemented) };
        }

        var session = new KClientSession(serviceName);
        int handle = ActiveHandleTable.CreateHandle(session);

        Logger.Info(nameof(IpcBridge), $"连接服务 \"{serviceName}\" → 句柄 0x{handle:X8}");
        return new SvcResult
        {
            ReturnCode = ResultCode.Success,
            ReturnValue1 = (ulong)handle
        };
    }

    // ──────────────────── SvcSendSyncRequest (0x21) ────────────────────

    /// <summary>
    /// 处理 SvcSendSyncRequest (SVC 0x21)
    /// X0 = 会话句柄
    /// IPC 缓冲区固定在 TLS + 0x100
    /// </summary>
    public SvcResult SendSyncRequest(SvcInfo svc)
    {
        int sessionHandle = (int)svc.X0;
        ulong bufferAddr = ActiveTlsAddress != 0 ? ActiveTlsAddress + 0x100 : 0;
        return ProcessIpcRequest(sessionHandle, bufferAddr);
    }

    // ──────────────────── SvcSendSyncRequestWithUserBuffer (0x22) ────────────────────

    /// <summary>
    /// 处理 SvcSendSyncRequestWithUserBuffer (SVC 0x22)
    /// X0 = IPC 缓冲区地址（用户指定）
    /// X1 = 会话句柄
    /// 与 SVC 0x21 相同逻辑，但使用用户指定的缓冲区而非 TLS+0x100
    /// </summary>
    public SvcResult SendSyncRequestWithUserBuffer(SvcInfo svc)
    {
        ulong bufferAddr = svc.X0;
        int sessionHandle = (int)svc.X1;
        return ProcessIpcRequest(sessionHandle, bufferAddr);
    }

    // ──────────────────── SvcReplyAndReceive (0x43) ────────────────────

    /// <summary>
    /// 处理 SvcReplyAndReceive (SVC 0x43)
    /// X1 = 句柄数组指针
    /// X2 = 句柄数量
    /// X3 = 回复目标句柄（0 = 不回复）
    /// X4 = 超时（纳秒，-1 = 无限等待）
    /// 返回: X0 = 结果码, X1 = 就绪句柄的索引
    ///
    /// 在 HLE 模型中，NRO 是客户端而非服务端，
    /// 此 SVC 通常不被 NRO 直接调用。
    /// 实现为简化版本：处理回复后立即返回 SessionClosed。
    /// </summary>
    public SvcResult ReplyAndReceive(SvcInfo svc)
    {
        if (ActiveHandleTable == null)
        {
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidState) };
        }

        ulong handlesPtr = svc.X1;
        int numHandles = (int)svc.X2;
        int replyTarget = (int)svc.X3;
        long timeoutNs = (long)svc.X4;

        Logger.Debug(nameof(IpcBridge),
            $"ReplyAndReceive: handles=0x{handlesPtr:X16} count={numHandles} " +
            $"replyTarget=0x{replyTarget:X8} timeout={timeoutNs}");

        // 验证句柄数组指针
        if (numHandles > 0 && handlesPtr == 0)
        {
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidAddress) };
        }

        // 如果指定了回复目标，向该会话写入空回复
        if (replyTarget != 0)
        {
            var replySession = ActiveHandleTable.GetObject<KClientSession>(replyTarget);
            if (replySession != null)
            {
                Logger.Debug(nameof(IpcBridge),
                    $"ReplyAndReceive: 回复已同步完成 → handle=0x{replyTarget:X8} (\"{replySession.ServicePortName}\")");
            }
        }

        // 在 HLE 模型中，NRO 是客户端，没有其他客户端会向 NRO 发送请求。
        // 返回 TimedOut（而非 SessionClosed）以防止 guest 在循环中无限重试导致 CPU 热循环。
        // TimedOut 让 guest 认为等待超时，通常会退避或重试而非崩溃。
        return new SvcResult
        {
            ReturnCode = ResultCode.KernelResult(TKernelResult.TimedOut),
            ReturnValue1 = 0
        };
    }

    // ──────────────────── SvcReplyAndReceiveWithUserBuffer (0x44) ────────────────────

    /// <summary>
    /// 处理 SvcReplyAndReceiveWithUserBuffer (SVC 0x44)
    /// X1 = IPC 缓冲区地址
    /// X2 = IPC 缓冲区大小
    /// X3 = 句柄数组指针
    /// X4 = 句柄数量
    /// X5 = 回复目标句柄（0 = 不回复）
    /// X6 = 超时（纳秒，-1 = 无限等待）
    /// 返回: X0 = 结果码, X1 = 就绪句柄的索引
    ///
    /// 与 SVC 0x43 相同逻辑，但使用用户指定的缓冲区
    /// </summary>
    public SvcResult ReplyAndReceiveWithUserBuffer(SvcInfo svc)
    {
        if (ActiveHandleTable == null)
        {
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidState) };
        }

        ulong bufferAddr = svc.X1;
        ulong bufferSize = svc.X2;
        ulong handlesPtr = svc.X3;
        int numHandles = (int)svc.X4;
        int replyTarget = (int)svc.X5;
        long timeoutNs = (long)svc.X6;

        Logger.Debug(nameof(IpcBridge),
            $"ReplyAndReceiveWithUserBuffer: buf=0x{bufferAddr:X16} size=0x{bufferSize:X} " +
            $"handles=0x{handlesPtr:X16} count={numHandles} " +
            $"replyTarget=0x{replyTarget:X8} timeout={timeoutNs}");

        // 验证句柄数组指针
        if (numHandles > 0 && handlesPtr == 0)
        {
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidAddress) };
        }

        // 如果指定了回复目标，处理回复
        if (replyTarget != 0)
        {
            var replySession = ActiveHandleTable.GetObject<KClientSession>(replyTarget);
            if (replySession != null)
            {
                Logger.Debug(nameof(IpcBridge),
                    $"ReplyAndReceiveWithUserBuffer: 回复已同步完成 → handle=0x{replyTarget:X8}");
            }
        }

        // 返回 TimedOut 防止 guest CPU 热循环（同 ReplyAndReceive）
        return new SvcResult
        {
            ReturnCode = ResultCode.KernelResult(TKernelResult.TimedOut),
            ReturnValue1 = 0
        };
    }

    // ──────────────────── 核心 IPC 处理逻辑 ────────────────────

    /// <summary>
    /// 处理同步 IPC 请求（SendSyncRequest / SendSyncRequestWithUserBuffer 共用）
    /// 从指定缓冲区解析 IPC 请求、分发到 HLE 服务、写回响应
    /// </summary>
    private SvcResult ProcessIpcRequest(int sessionHandle, ulong bufferAddr)
    {
        if (ActiveHandleTable == null)
        {
            Logger.Error(nameof(IpcBridge), "ProcessIpcRequest: 无活跃进程句柄表");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidState) };
        }

        if (bufferAddr == 0)
        {
            Logger.Error(nameof(IpcBridge), "ProcessIpcRequest: IPC 缓冲区地址为 0");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidAddress) };
        }

        // 从句柄表查找会话对象，获取服务端口名称
        var session = ActiveHandleTable.GetObject<KClientSession>(sessionHandle);
        if (session == null)
        {
            Logger.Warning(nameof(IpcBridge), $"无效会话句柄 0x{sessionHandle:X8}");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidHandle) };
        }

        string portName = session.ServicePortName;
        Logger.Info(nameof(IpcBridge),
            $"IPC 请求: handle=0x{sessionHandle:X8} → \"{portName}\" buf=0x{bufferAddr:X16} cmd={IpcMessageParser.ReadCommandId(bufferAddr, _memory)}");

        try
        {
            // 从 guest 内存解析 IPC 请求
            var request = IpcMessageParser.ParseRequest(bufferAddr, _memory);

            // 处理 Close 命令：关闭会话句柄
            if (request.Header.CommandType == IpcCommandType.Close ||
                request.Header.CommandType == IpcCommandType.TipcClose)
            {
                ActiveHandleTable.CloseHandle(sessionHandle);
                Logger.Info(nameof(IpcBridge), $"关闭会话: handle=0x{sessionHandle:X8} (\"{portName}\")");

                var closeResponse = new IpcResponse();
                IpcMessageParser.WriteResponse(bufferAddr, _memory, closeResponse, request.Header.CommandType);
                return new SvcResult { ReturnCode = ResultCode.Success };
            }

            // 分发到 HLE 服务处理
            var response = new IpcResponse();
            var result = _serviceManager.HandleRequest(portName, request, ref response);

            if (!result.IsSuccess)
            {
                Logger.Warning(nameof(IpcBridge),
                    $"IPC 请求失败: \"{portName}\" cmd={request.CommandId} → {result}");
                response.ResultCode = result;
            }

            // 句柄解析：ServiceHandleFactory 必须在使用 IpcBridge 前设置
            if (_serviceManager.ServiceHandleFactory == null)
            {
                Logger.Warning(nameof(IpcBridge),
                    "ServiceHandleFactory 未设置，CopyHandles 中的句柄无法映射到 HandleTable。" +
                    "响应中的句柄将保持原始值，guest 可能无法使用这些句柄。");
            }

            // 将响应写回 guest 内存
            IpcMessageParser.WriteResponse(bufferAddr, _memory, response, request.Header.CommandType);

            Logger.Info(nameof(IpcBridge),
                $"IPC 完成: \"{portName}\" cmd={request.CommandId} → {result} " +
                $"data={response.Data.Count}B handles={response.CopyHandles.Count}");

            return new SvcResult { ReturnCode = ResultCode.Success };
        }
        catch (Exception ex)
        {
            Logger.Error(nameof(IpcBridge), $"IPC 处理异常: {ex}");
            return new SvcResult { ReturnCode = ResultCode.KernelResult(TKernelResult.InvalidState) };
        }
    }

    // ──────────────────── 辅助方法 ────────────────────

    /// <summary>
    /// 从 guest 内存读取服务名称
    /// Horizon OS 服务名: null-terminated ASCII，最长 12 字节（含 null），8 字节对齐
    /// </summary>
    private string ReadServiceNameFromGuest(ulong address)
    {
        try
        {
            var buf = new byte[12];
            _memory.Read(address, buf);
            int len = Array.IndexOf(buf, (byte)0);
            if (len < 0) len = 12;
            return Encoding.ASCII.GetString(buf, 0, len);
        }
        catch (Exception ex)
        {
            Logger.Warning(nameof(IpcBridge), $"读取服务名失败 @ 0x{address:X16}: {ex.Message}");
            return "";
        }
    }
}

using System;
